#include<bits/stdc++.h>
using namespace std;
int dp[50][50][50][50];
int k[5], n, m;
int b[1000];
int main() {
	cin >> n >> m;
	for (int i = 1; i <= n; i++) {
		cin >> b[i];
	}
	dp[0][0][0][0]=b[1];
	for (int i = 1; i <= m; i++) {
		int x;
		cin >> x;
		k[x]++;
	}
	for (int i = 0; i <= k[1]; i++) {
		for (int j = 0; j <= k[2]; j++) {
			for (int i2 = 0; i2 <= k[3]; i2++) {
				for (int j2 = 0; j2 <= k[4]; j2++) {
					int r = 1+i + j * 2 + i2 * 3 + j2 * 4;
					if (i != 0)	dp[i][j][i2][j2] = max(dp[i][j][i2][j2], dp[i - 1][j][i2][j2] + b[r]);
					if (j != 0)    dp[i][j][i2][j2] = max(dp[i][j][i2][j2], dp[i][j - 1][i2][j2] + b[r]);
					if (i2 != 0)    dp[i][j][i2][j2] = max(dp[i][j][i2][j2], dp[i][j][i2 - 1][j2] + b[r]);
					if (j2 != 0)	dp[i][j][i2][j2] = max(dp[i][j][i2][j2], dp[i][j][i2][j2 - 1] + b[r]);
				}
			}
		}
	}
	cout<<dp[k[1]][k[2]][k[3]][k[4]];

	return 0;
}
